import { useState } from "react";
import { Scanner } from "@yudiel/react-qr-scanner";
import "./App.css";

function App() {
  const [cameraActive, setCameraActive] = useState(false); // start: false!
  const [permissionAsked, setPermissionAsked] = useState(false);
  const [flashOn, setFlashOn] = useState(false);
  const [facingMode, setFacingMode] = useState("environment");
  const [lastResult, setLastResult] = useState("Brak danych");
  const [history, setHistory] = useState([]);

  const beep = () => {
    const audio = new Audio("https://actions.google.com/sounds/v1/alarms/beep_short.ogg");
    audio.play().catch(() => {});
  };

  const vibrate = () => {
    if (navigator.vibrate) navigator.vibrate(200);
  };

  const handleScan = (results) => {
    if (results?.length > 0) {
      const value = results[0]?.rawValue;
      if (value && value !== lastResult) {
        setLastResult(value);
        setHistory((prev) => [value, ...prev]);
        beep();
        vibrate();
      }
    }
  };

  const startScanner = () => {
    setCameraActive(true);
    setPermissionAsked(true);
  };

  return (
    <div className="App">
      <header className="App-header">
        <h1>Czytnik kodów QR</h1>

        {/* Ekran startowy – ZMUSZAMY użytkownika do tapnięcia */}
        {!permissionAsked && (
          <div className="start-screen">
            <p>Aby rozpocząć skanowanie, naciśnij przycisk poniżej</p>
            <button className="big-start-btn" onClick={startScanner}>
              Uruchom skaner QR
            </button>
          </div>
        )}

        {/* Kontrolki i skaner – widoczne dopiero po zgodzie */}
        {permissionAsked && (
          <>
            <div className="controls">
              <button onClick={() => setCameraActive((prev) => !prev)}>
                {cameraActive ? "Stop kamera" : "Start kamera"}
              </button>

              <button
                onClick={() =>
                  setFacingMode(facingMode === "environment" ? "user" : "environment")
                }
              >
                Zmień kamerę
              </button>

              <button onClick={() => setFlashOn((prev) => !prev)}>
                {flashOn ? "Latarka OFF" : "Latarka ON"}
              </button>
            </div>

            {cameraActive && (
              <div className="scanner-box">
                <Scanner
                  onScan={handleScan}
                  components={{ torch: flashOn }}
                  constraints={{ facingMode }}
                  styles={{
                    container: { width: "100%", maxWidth: "400px" },
                    video: { borderRadius: "12px" },
                  }}
                />
              </div>
            )}

            <div className="result">
              <h2>Ostatni wynik:</h2>
              <p>{lastResult}</p>
            </div>

            <div className="history">
              <h3>Historia skanów:</h3>
              <ul>
                {history.map((h, i) => (
                  <li key={i}>{h}</li>
                ))}
              </ul>
            </div>
          </>
        )}
      </header>
    </div>
  );
}

export default App;
